    async setImageQuality(imageQuality) {
        let jpegQuality = null;
        let dngBitDepth = null;
        const hasDngMatch = imageQuality.match(/^DNG (12|14)bit(?: \+ ([a-z]+))?/i);
        if (hasDngMatch) {
            const [, dngBitDepthStr, jpegQualityStr] = hasDngMatch;
            jpegQuality = jpegQualityStr ?? null;
            dngBitDepth = parseInt(dngBitDepthStr);
        } else jpegQuality = imageQuality;
        // Generate imageQuality value for setCamData
        let imageQualityID;
        switch(jpegQuality){
            case null:
                imageQualityID = 0;
                break;
            case 'fine':
                imageQualityID = 2;
                break;
            case 'standard':
                imageQualityID = 4;
                break;
            case 'low':
                imageQualityID = 8;
                break;
            default:
                return 'invalid';
        }
        imageQualityID |= dngBitDepth === null ? 0 : 16;
        const setImageQualityResult = await this.setCamData(OpCodeSigma.SetCamDataGroup2, 15, imageQualityID);
        let setDngBitDepthResult = 'ok';
        if (dngBitDepth !== null) setDngBitDepthResult = await this.setCamData(OpCodeSigma.SetCamDataGroup4, 9, dngBitDepth);
        if (setImageQualityResult === 'ok' && setDngBitDepthResult === 'ok') return 'ok';
        else return 'invalid';
    }
    async getImageQualityDesc() {
        const imageQuality = await (async ()=>{
            const { imageQuality: imageQuality1  } = await this.getCamDataGroup2();
            let jpegQuality = null;
            switch(imageQuality1 & 15){
                case 2:
                    jpegQuality = 'fine';
                    break;
                case 4:
                    jpegQuality = 'standard';
                    break;
                case 8:
                    jpegQuality = 'low';
                    break;
            }
            const hasDNG = !!(imageQuality1 & 16);
            return {
                jpegQuality,
                hasDNG
            };
        })();
        const dngBitDepth = await (async ()=>{
            const { dngImageQuality  } = await this.getCamDataGroup4();
            return dngImageQuality + 'bit';
        })();
        function stringifyImageQuality(quality, dngBitDepth1 = '') {
            if (quality.hasDNG) {
                if (quality.jpegQuality) {
                    return `DNG ${dngBitDepth1} + ${quality.jpegQuality}`;
                } else {
                    return `DNG ${dngBitDepth1}`;
                }
            } else {
                if (quality.jpegQuality) {
                    return quality.jpegQuality;
                } else {
                    throw new Error('Invalid ImageQualityConfig');
                }
            }
        }
        return {
            writable: true,
            value: stringifyImageQuality(imageQuality, dngBitDepth),
            options: [
                // NOTE: Hard-coded so this might not work for some cases
                'low',
                'standard',
                'fine',
                'raw 12bit + fine',
                'raw 14bit + fine',
                'raw 12bit',
                'raw 14bit', 
            ]
        };
    }
